$$, $$602403ce95c69f9633f54840952ed95cfb070bbf99ba225ed8b0236f06508913$$, $${"A": "9b25c63112c057c33815ed9f93a4fa0828ab3fc0feaf29f22d2d0d787ff0970a", "C": "d4fdf923ba776b98bda680220afe7660b2fb7f78e25f4cb026ad0b29031d9620", "D": "b3f9d1404d9fe880daee47d79fac0941133035ee53aeaeeab8236a7c3178dfaa"}$$::jsonb, $$Budget J-Books/FY26/USAF/FY26 Space Force Research and Development Test and Evaluation.pdf$$, 563, $$2026-05-07T23:57:02.622579+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0204228N$$, 2027, $$Effective in FY 2026, Project 3311 Navigation Systems moved from PE 0204228N to PE 0607658N as part of the PE/BLI consolidation effort in the DoW Implementation
Plan from the Commission on PPBE Reform Final Report.

The Surface Support RDT&E funding will be used for the research, design, development, integration testing, and documentation of the Inertial Navigation System
(INS) AN/WSN-12 for all Navy ships and submarines. The INS provides mission critical ship position and attitude data to shipboard sensors (such as radars), combat
and weapon systems. The INS uses data from the Global Positioning System (GPS) to periodically update (i.e., reset) its position and internal clock. The INS is the
ship's primary position source in the absence of GPS, and it consists of an Inertial Sensor Module (ISM) and a Navigation Processing Module (NPM) that will provide a
significant improvement with respect to attitude and velocity data over previous INS. RDT&E funding will support continued system design to create a baseline for Pre-
Production Units (PPU), Low Rate Initial Production (LRIP), and Full Rate Production (FRP).

Military GPS User Equipment (MGUE) will provide assured Positioning, Navigation, and Timing (PNT) in a GPS degraded environment. Funding will be used for the
development of interface and performance requirements, shipboard system architecture definition, and MGUE integration.

Submarine Speed Sensors will provide investigation, development, testing and integration of new Own-Ship Speed sensors to address new capabilities, reduce
detection, and improve reliability.

Automated Celestial Navigation System (ACNS) funding will be used for the research, development, Engineering Development Model (EDM), documentation and
integration testing of the celestial navigation solution for the NoGAPSS navigation implementation on the fleet. Efforts will leverage ONR celestial navigation research
into a reproducible ruggedized system fully integrated into the navigation suite.$$, $$Effective in FY 2026, Project 3311 Navigation Systems moved from PE 0204228N to PE 0607658N as part of the PE/BLI consolidation effort in the DoW Implementation
Plan from the Commission on PPBE Reform Final Report.

The Surface Support RDT&E funding will be used for the research, design, development, integration testing, and documentation of the Inertial Navigation System
(INS) AN/WSN-12 for all Navy ships and submarines. The INS provides mission critical ship position and attitude data to shipboard sensors (such as radars), combat
and weapon systems. The INS uses data from the Global Positioning System (GPS) to periodically update (i.e., reset) its position and internal clock. The INS is the
ship's primary position source in the absence of GPS, and it consists of an Inertial Sensor Module (ISM) and a Navigation Processing Module (NPM) that will provide a
significant improvement with respect to attitude and velocity data over previous INS. RDT&E funding will support continued system design to create a baseline for Pre-
Production Units (PPU), Low Rate Initial Production (LRIP), and Full Rate Production (FRP).

Military GPS User Equipment (MGUE) will provide assured Positioning, Navigation, and Timing (PNT) in a GPS degraded environment. Funding will be used for the
development of interface and performance requirements, shipboard system architecture definition, and MGUE integration.

Submarine Speed Sensors will provide investigation, development, testing and integration of new Own-Ship Speed sensors to address new capabilities, reduce
detection, and improve reliability.

Automated Celestial Navigation System (ACNS) funding will be used for the research, development, Engineering Development Model (EDM), documentation and
integration testing of the celestial navigation solution for the NoGAPSS navigation implementation on the fleet. Efforts will leverage ONR celestial navigation research
into a reproducible ruggedized system fully integrated into the navigation suite.

