$$, $$be4fb0c7b5d4a4ccce4b97586911a6864b18d7496d87c40e8d6bd2ca3032dfe7$$, $${"A": "b6ed8dd7ee076559ae8fc5e864d9a562063454a384aeec8c42bac7021eeaf820", "C": "241d9712b7eaa05264631fa9726eb930531a8941a2d607d0ba8cd29adcf940c9", "D": "ce5c5f40d076f45a087df6d3a79bbfe80a9578b43b3e6d76fccfe3e6a166de62"}$$::jsonb, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$, 489, $$2026-05-07T23:11:07.973865+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0605712F$$, 2026, $$The program element funds the Air Force Operational Test and Evaluation Center (AFOTEC) to conduct Congressionally mandated Initial Operational Test and
Evaluation (IOT&E) to support major weapon system acquisition decisions beyond Low-Rate Initial Production (LRIP), Milestone C, full rate production, fielding, and
declaration of Initial Operational Capability (IOC). For Major Defense Acquisition Programs (MDAP), the law requires IOT&E be completed under realistic operating
conditions before proceeding beyond LRIP. IOT&E is planned to answer all critical operational issues (COI) as thoroughly as possible. IOT&E is conducted to determine
the operational effectiveness and suitability, and resolve overall mission capability, of systems undergoing research and development (R&D) efforts. It is an evaluation
of a system's performance when the complete system is tested and evaluated against operational criteria by personnel with the same qualifications as those who will
operate, maintain, and support the system when deployed. In general, IOT&E is performed on new systems in development, major modifications, and other systems as
directed. This PE also funds participation in Multiservice Operational Test and Evaluation (MOT&E), and Follow-on Operational Test and Evaluation (FOT&E) when it
is the continuation of IOT&E activities passed the full rate production decision. FOT&E answers specific questions about unresolved COIs and test issues or completes
areas not finished during the IOT&E. The PE funds related Operational Test & Evaluation (OT&E) activities such as conducting Continuous Operational Testing (COT),
Early Influence, agile release tests, Integrated Test and Evaluation (IT&E), Operational Utility Evaluations (OUE), Early Operational Assessments (EOA), Operational
Assessments (OA) and operationally realistic evaluations of advanced technologies which informs military utility determination. These tests support releases and major
milestones and decision points prior to Milestone C, full rate production, fielding, or declaration of IOC. IOT&E programs are identified in four system categories: Air;
Weapons; Command, Control, Communications, Computers, Intelligence, Surveillance and Reconnaissance (C4ISR); and Combat Support. This program element is
driven by Congressional and DoD acquisition-mandated requirements for operational testing. AFOTEC schedules and executes tests according to the forecasted test
readiness of the MDAP program offices.

 This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to
 sustain and/or modernize the installations or operations required for general research, development, test and evaluation.

