INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$1105219BB$$, 2026, $$This Program Element (PE) identifies, develops, rapidly prototypes, integrates, and tests Special Operations (SO)-peculiar mission kits, mission payloads, weapons,
and modifications on MQ-9 Unmanned Aerial Vehicles (UAVs), Ground Control Stations (GCSs), and training systems as a component of the Medium Altitude Long
Endurance Tactical (MALET) program. The United States Special Operations Command (USSOCOM) is designated as the DoD lead for planning, synchronizing, and as
directed, executing global operations against terrorist networks. The USSOCOM requires the capability to find, fix, finish, exploit, and analyze time-sensitive high-value
targets. These targets can often only be identified with patient collection of information and require rapid, decisive action during the short periods in which they present
themselves. This program element addresses the primary areas of Intelligence, Surveillance, Reconnaissance, and Target Acquisition and Strike. This PE received
Congressional Add funding in FY 2024 for Adaptive Airborne Enterprise ($55.000 million).

Beginning in FY 2026, all MQ-9 RDT&E funding has transitioned to PE 1160403BB, Aviation Systems, Project SF100: Aviation Systems Advanced Development, to
support the acceleration of the A2E concept.

The total cost of the MQ-9 Middle Tier of Acquisition effort is $240.605 million, including RDT&E and procurement of prototype units. The MQ-9 is fully funded through
completion in FY 2025.$$, $$As the supported Combatant Command in global operations, the United States Special Operations Command (USSOCOM) requires the capability to find, fix, finish,
exploit, and analyze time-sensitive high-value targets. These targets can often only be identified with patient collection of information and require rapid, decisive
action during the short periods in which they present themselves. This project addresses the primary areas of Intelligence, Surveillance, Reconnaissance, and Target
Acquisition and Strike. The majority of the developmental funds provides for the Operational Flight Program (OFP) Software for the aircraft, Ground Control Station
(GCS), and turret. Special Operations-peculiar (SO-p) modifications to the OFP allow for a rapid integration of emerging capabilities in order to maintain relevance and
dominance of the MQ-9.

