INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0601117E$$, 2026, $$The Basic Operational Medical Science Program Element (PE) will explore and develop basic research in medical-related information and technology leading to
fundamental discoveries, tools, and applications critical to overcoming DoD challenges. This PE will address the Department's identified need for warfighter medical
care related to prevention and treatment of infectious disease, real-time healthcare interventions of acute and chronic illness and injury, and interventions for improved
warfighter resilience and performance against operational stressors. This PE also supports innovation and robust transition planning in the technology cycle by working
with entrepreneurs to increase the likelihood that DARPA-funded technologies take root in the U.S. and provide new capabilities for national defense.

